cd C:/Users/0000250059 && powershell.exe -NoProfile -Command '
# Use the registry provider directly with the literal path
$parent = Get-Item "HKCU:\Console"
$subkeys = $parent.GetSubKeyNames()
foreach ($name in $subkeys) {
    if ($name -match "Startup" -and $name -ne "%%Startup") {
        Write-Host "Removing bad key: [$name]"
        $parent.DeleteSubKeyTree($name)
    }
}
# Verify
Get-ChildItem "HKCU:\Console" | Where-Object { $_.Name -match "Startup" } | ForEach-Object { $_.Name }
'

