# 1. Check registry
Write-Host "=== Registry Check ==="
$regPath = "HKCU:\Console\%%Startup"
$props = Get-ItemProperty $regPath -ErrorAction SilentlyContinue
if ($props.DelegationConsole -eq "{2EACA947-7F5F-4CFA-BA87-8F7FBEEFBE69}") {
    Write-Host "[OK] DelegationConsole = Windows Terminal"
} else {
    Write-Host "[FAIL] DelegationConsole = $($props.DelegationConsole)"
}
if ($props.DelegationTerminal -eq "{E12CFF52-A866-4C77-9A90-F570A7AA2C6B}") {
    Write-Host "[OK] DelegationTerminal = Windows Terminal"
} else {
    Write-Host "[FAIL] DelegationTerminal = $($props.DelegationTerminal)"
}

# 2. Check Windows Terminal settings
Write-Host ""
Write-Host "=== Windows Terminal Settings ==="
$wtSettings = Get-Content "$env:LOCALAPPDATA\Packages\Microsoft.WindowsTerminal_8wekyb3d8bbwe\LocalState\settings.json" -Raw | ConvertFrom-Json
$hasConflict = $false
foreach ($kb in $wtSettings.keybindings) {
    if ($kb.keys -eq "ctrl+shift+n") {
        Write-Host "[FAIL] ctrl+shift+n is still bound to: $($kb.id)"
        $hasConflict = $true
    }
}
if (-not $hasConflict) {
    Write-Host "[OK] ctrl+shift+n is not overridden (defaults to newWindow)"
}

Write-Host ""
Write-Host "=== Default Profile ==="
Write-Host "defaultProfile: $($wtSettings.defaultProfile)"
$match = $wtSettings.profiles.list | Where-Object { $_.guid -eq $wtSettings.defaultProfile }
if ($match) {
    Write-Host "[OK] Default profile: $($match.name) (source: $($match.source))"
} else {
    Write-Host "[WARN] Could not find matching profile"
}

# 3. Check VS Code keybindings
Write-Host ""
Write-Host "=== VS Code keybindings.json ==="
$kb = Get-Content "$env:APPDATA\Code\User\keybindings.json" -Raw | ConvertFrom-Json
$ctrltt = $kb | Where-Object { $_.key -eq "ctrl+t ctrl+t" -and $_.command -eq "workbench.action.terminal.openNativeConsole" }
if ($ctrltt) {
    Write-Host "[OK] ctrl+t ctrl+t -> openNativeConsole"
} else {
    Write-Host "[FAIL] ctrl+t ctrl+t binding not found"
}
'
